  ('medical-tech-moex-21118', 'medical-tech', 'medical-tech-moex-093-5c00801d', 'sub-medical-tech-13', NULL, 'single_choice', '腦脊髓液（CSF）若外觀呈xanthochromia，是指下列何種意義？ 脊髓穿刺創傷造成新鮮檢體外觀呈紅色 巨噬細胞中含有多量的hemosiderin 穿刺創傷造成血漿中的纖維蛋白原跑到CSF中，造成凝固 CSF經離心後，上清液呈粉紅色、橘色或黃色', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:17+00:00", "source_pdf_sha1": "c9542f67b3c1", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "093120", "c": "105", "s": "3001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "臨床鏡檢學(包括寄生蟲學)", "year": "093", "exam_name": "093年第二次專技醫事人員、中醫師、營養師、心理師、呼吸治療師、獸醫人員考試", "original_question_number": 44, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
